import React from "react";

export default function BottomBar({ onTabChange }) {
  return (
    <nav className="fixed bottom-0 left-0 right-0 z-40">
      <div className="mx-auto max-w-4xl px-4 pb-4">
        <div className="rounded-2xl px-2 py-1 border border-white/10 bg-white/20 dark:bg-white/10 backdrop-blur shadow-lg flex items-center justify-around">
          <Tab iconPath="M3 12l9-9 9 9v9a3 3 0 0 1-3 3H6a3 3 0 0 1-3-3v-9z" label="Now" onClick={() => onTabChange && onTabChange("now")} />
          <Tab iconPath="M4 6h16M4 12h16M4 18h16" label="Hourly" onClick={() => onTabChange && onTabChange("hourly")} />
          <Tab iconPath="M5 12l5 5L20 7" label="Forecast" onClick={() => onTabChange && onTabChange("forecast")} />
          <Tab iconPath="M12 2a10 10 0 1 1 0 20 10 10 0 0 1 0-20z" label="Radar" onClick={() => onTabChange && onTabChange("radar")} />
        </div>
      </div>
    </nav>
  );
}

function Tab({ iconPath, label, onClick }) {
  return (
    <button onClick={onClick} className="flex flex-col items-center gap-0.5 px-3 py-2 rounded-xl hover:bg-white/20">
      <svg className="w-5 h-5" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d={iconPath} /></svg>
      <span className="text-[11px] opacity-80">{label}</span>
    </button>
  );
}
